declare global {
  interface Window {
    model3d?: Record<string, THREE.Mesh>
    model3d_material?: Record<string, THREE.Material[]>
  }
}

class CustomSinCurve extends THREE.Curve<THREE.Vector3> {
  scale: number

  constructor(scale = 1) {
    super()
    this.scale = scale
  }

  getPoint(t: number, optionalTarget = new THREE.Vector3()) {
    const tx = t * 3 - 1.5
    const ty = t
    const tz = 0
    return optionalTarget.set(tx, ty, tz).multiplyScalar(this.scale)
  }
}

export interface Model3dGeometryTubeProps {
  /** 网格配置 */
  meshConfig?: {
    visible?: boolean
    position?: { x?: number; y?: number; z?: number }
    scale?: { x?: number; y?: number; z?: number }
    rotation?: { x?: number; y?: number; z?: number }
    opacity?: number
    color?: string
  }
  /** 材质配置 */
  materialsConfig?: {
    materials?: any[]
  }
  /** 编辑模式 */
  editMode?: boolean
  /** 名称 */
  name?: string
  /** 点击回调 */
  onClick?: () => void
  /** 曲线参数 [曲线, 管状分段, 半径, 径向分段, 是否闭合] */
  args?: [THREE.Curve<THREE.Vector3>, number, number, number, boolean]
}

const Model3dGeometryTube: React.FC<Model3dGeometryTubeProps> = ({
  meshConfig = {},
  materialsConfig = {},
  editMode = false,
  name = "",
  onClick,
  args,
}) => {
  const { visible, position, scale, rotation, opacity, color } = meshConfig
  const { materials } = materialsConfig

  // 避免未使用参数警告
  if (materials) {
    // 材质配置占位
  }

  const meshRef = React.useRef<THREE.Mesh>(null)
  const materialRef = React.useRef<THREE.MeshPhysicalMaterial>(null)

  React.useEffect(() => {
    if (meshRef.current && materialRef.current) {
      // 原逻辑：将 mesh 和 material 存储到全局对象
      if (!window.model3d) {
        window.model3d = {}
      }
      if (!window.model3d_material) {
        window.model3d_material = {}
      }
      window.model3d[name] = meshRef.current
      window.model3d_material[name] = [materialRef.current]
    }
  }, [name])

  const gProps = {
    visible: visible,
    position: [position?.x || 0, position?.y || 0, position?.z || 0] as [number, number, number],
    scale: [scale?.x || 1, scale?.y || 1, scale?.z || 1] as [number, number, number],
    rotation: [
      THREE.MathUtils.degToRad(rotation?.x || 0),
      THREE.MathUtils.degToRad(rotation?.y || 0),
      THREE.MathUtils.degToRad(rotation?.z || 0),
    ] as [number, number, number],
    receiveShadow: true,
    castShadow: true,
    onClick: (e: any) => {
      e.stopPropagation()
      onClick?.()
      if (editMode) {
        // 编辑模式下的逻辑
        console.log("Tube clicked in edit mode", name)
      }
    },
  }

  const mProps = {
    opacity: opacity,
    transparent: true,
    alphaTest: opacity,
    color: color ? new THREE.Color(color) : undefined,
  }

  // 默认曲线
  const curve = React.useMemo(() => new CustomSinCurve(10), [])
  const tubeArgs = args || [curve, 20, 2, 8, false]

  return (
    <Tube ref={meshRef} name={name} args={tubeArgs} {...gProps}>
      <meshPhysicalMaterial ref={materialRef} {...mProps} />
    </Tube>
  )
}

Model3dGeometryTube.displayName = "Model3dGeometryTube"

export { Model3dGeometryTube }

import { FormProvider, useForm, type UseFormPropsExtended } from '@airiot/client'
import type { ReactNode } from 'react'

type FormProps = UseFormPropsExtended & {
  formId: string
  children: ReactNode
  onSubmit: (data: any) => void
}

const Form = ({ formId, children, onSubmit, onEffect, ...props } : FormProps ) => {
  const methods = useForm({ ...props, onEffect })
  return (
    <FormProvider {...methods}>
      <form id={formId} onSubmit={methods.handleSubmit(onSubmit)}>
        {children}
      </form>
    </FormProvider>
  )
}

export default Form

import { Button } from "@/components/ui/button"
import {
  Field,
  FieldDescription,
  FieldError,
  FieldLabel,
} from "@/components/ui/field"
import { Input } from '@/components/ui/input'
import { Controller, useFieldUIStateValue, useFormContext } from '@airiot/client'
import type { ReactNode } from 'react'
import React, { cloneElement } from 'react'
import fieldMap from './field-map'

const FormField = ({ name, label, type, description, children, required, rules, ...restProps }: { name: string, label?: ReactNode, type?: string, description?: ReactNode, children?: ReactNode | ((props: any) => ReactNode), required?: boolean, rules?: any, [key: string]: any }) => {
  let methods = null
  try {
    methods = useFormContext()
  } catch {
    return <Button variant={"destructive"}>FormField must be used within a Form.</Button>
  }

  const ui = useFieldUIStateValue(name)
  const ContorlComponent = type && fieldMap[type] || Input
  const fieldId = `form-rhf-${name}` + (Math.random().toString(36).substr(2, 9))

  return ui.visible ? (
    <Controller
        name={name}
        control={methods?.control}
        rules={{ required, ...rules }}
        render={({ field, fieldState }) => (
        <Field data-invalid={fieldState.invalid}>
          <FieldLabel htmlFor={fieldId}>
            {label || name}{required && <span className="text-red-500">*</span>}
          </FieldLabel>
          {
            children ? ( typeof children === 'function' ? children({
              id: fieldId,
              ...field,
              ...restProps,
              ref: null,
              'aria-invalid': fieldState.invalid
            }) : cloneElement(children as React.ReactElement, {
              id: fieldId,
              ...field,
              ...restProps,
              ref: null,
              'aria-invalid': fieldState.invalid
            }) ) : (
              <ContorlComponent
                id={fieldId}
                {...field}
                {...restProps}
                ref={null}
                aria-invalid={fieldState.invalid}
              />
            )
          }
          {description && (
            <FieldDescription>
              {description}
            </FieldDescription>
          )}
          {fieldState.invalid && (
            <FieldError errors={[fieldState.error]} />
          )}
        </Field>
      )}
    />
  ) : null
}

export default FormField

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"
import { cn } from "@/lib/utils"

const barVariants = cva(
  "relative border transition-colors",
  {
    variants: {
      variant: {
        default: "border-border bg-background",
        outline: "border-2 border-primary",
        filled: "border-primary/20 bg-primary/5",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

export interface VisualMapItem {
  data: number
  color: string
}

export interface BarProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof barVariants> {
  /**
   * 当前值
   */
  value?: number
  /**
   * 最大值，默认100
   */
  maxValue?: number
  /**
   * 进度条填充颜色
   */
  color?: string
  /**
   * 边框颜色
   */
  borderColor?: string
  /**
   * 颜色映射配置
   */
  visualMap?: VisualMapItem[]
  /**
   * 方向：垂直或水平
   */
  direction?: "vertical" | "horizontal"
  /**
   * 起始位置
   */
  position?: "start" | "end"
  /**
   * 单元格键值
   */
  cellKey?: string
}

const Bar = React.forwardRef<HTMLDivElement, BarProps>(
  (
    {
      className,
      value = 0,
      maxValue = 100,
      color = "#000",
      borderColor,
      visualMap = [],
      direction = "horizontal",
      position = "start",
      variant,
      cellKey,
      ...props
    },
    ref
  ) => {
    // 计算实际值
    const computValue = React.useMemo(() => {
      return value
    }, [value])

    // 计算颜色
    const fillColor = React.useMemo(() => {
      // 如果有颜色映射，根据值查找对应颜色
      if (visualMap && visualMap.length > 0) {
        const sortedMap = [...visualMap].sort((a, b) => a.data - b.data)
        let matchedColor: string | null = null
        sortedMap.forEach((item) => {
          if (computValue >= item.data) {
            matchedColor = item.color
          }
        })
        if (matchedColor) {
          return matchedColor
        }
      }
      return color
    }, [visualMap, computValue, color])

    // 计算进度百分比
    const percentage = React.useMemo(() => {
      const val = computValue !== undefined ? computValue : 0
      return Math.min(Math.max((val / maxValue) * 100, 0), 100)
    }, [computValue, maxValue])

    // 垂直进度条样式
    if (direction === "vertical") {
      const isFromBottom = position === "start"
      const heightStyle = isFromBottom ? { bottom: 0 } : { top: 0 }

      return (
        <div
          ref={ref}
          className={cn(
            "bar-component relative w-full h-full overflow-hidden",
            barVariants({ variant }),
            className
          )}
          style={{
            borderColor: borderColor || undefined,
            ...props.style
          }}
          {...props}
        >
          <div
            className="absolute left-0 right-0 bg-current transition-all duration-300 ease-in-out"
            style={{
              ...heightStyle,
              height: `${percentage}%`,
              backgroundColor: fillColor,
              color: fillColor,
            }}
          />
        </div>
      )
    }

    // 水平进度条
    const isFromLeft = position === "start"
    const horizontalStyle = isFromLeft ? { left: 0 } : { right: 0 }

    return (
      <div
        ref={ref}
        className={cn(
          "bar-component relative w-full h-full overflow-hidden",
          barVariants({ variant }),
          className
        )}
        style={{
          borderColor: borderColor || undefined,
          ...props.style
        }}
        {...props}
      >
        <div
          className="absolute top-0 bottom-0 bg-current transition-all duration-300 ease-in-out"
          style={{
            ...horizontalStyle,
            width: `${percentage}%`,
            backgroundColor: fillColor,
            color: fillColor,
          }}
        />
      </div>
    )
  }
)
Bar.displayName = "Bar"

export { Bar, barVariants }

